async function loadRuntimeIdentity(){try{const payload=await api('/api/runtime');const kind=runtimeIdentityState(payload);state.runtimeIdentityResolved=kind!=='unknown';state.runtimeIdentity={state:kind,label:kind==='canonical'?'CANONICAL PRODUCTION':kind==='isolated'?'ISOLATED / NON-PRODUCTION':'RUNTIME UNKNOWN',data_root:payload?.data_root||null,short_data_root:payload?.data_root?shortDataRoot(payload.data_root):'Runtime path unavailable',title:payload?.data_root?`Data root: ${payload.data_root}`:'Runtime identity unavailable'};renderRuntimeIdentity();syncMutationControls()}catch(e){setRuntimeUnknown('Runtime identity unavailable');toast(e.message,true)}}
async function init(){setRuntimeUnknown('Resolving runtime identity…');try{state.config=await api('/api/config');$('#health').textContent=`Gemini: ${state.config.gemini_configured?'sẵn sàng':'chưa có key'} · VieNeu: ${state.config.tts_status}`;$('#epubPath').innerHTML=state.config.available_epubs.map(p=>`<option value="${p}">${p.split(/[\\/]/).pop()}</option>`).join('')||'<option>Không tìm thấy EPUB</option>'}catch(e){toast(e.message,true)}await loadRuntimeIdentity();try{await loadBooks();await loadJobs()}catch(e){toast(e.message,true)}setInterval(loadJobs,2500)}
function isSmokeBook(title){const smokePat=/smoke|speaker\s+review\s+smoke|character\s+bible\s+smoke/i;return smokePat.test(title)}
async function loadBooks(){state.books=await api('/api/books');const filtered=state.showSmokeBooks?state.books:state.books.filter(b=>!isSmokeBook(b.title));$('#books').innerHTML=filtered.map(b=>`<div class="book-card ${state.book?.id===b.id?'active':''}" data-id="${b.id}"><strong>${esc(b.title)}</strong><span>${esc(b.author||'Không rõ tác giả')} · ${b.chapter_count} chương · ${b.audio_chapters||0} có audio</span></div>`).join('')||'<p class="muted">Chưa nhập sách.</p>';document.querySelectorAll('.book-card').forEach(el=>el.onclick=()=>selectBook(+el.dataset.id))}
async function selectBook(id){state.book=state.books.find(b=>b.id===id);state.page=0;state.previewOk=false;$('#workspace').classList.remove('hidden');$('#bookTitle').textContent=state.book.title;$('#chapterCount').textContent=`${state.book.chapter_count} chương`;$('#fromChapter').value=1;$('#toChapter').value=Math.min(10,state.book.chapter_count);await loadBooks();await loadChapters()}
function chapterStatusSummary(chapter){if(chapter.active_output_has_trustworthy_binding&&chapter.active_output_job_id){const plan=chapter.active_output_casting_plan_revision?` | Plan v${chapter.active_output_casting_plan_revision}`:'';return {label:'ACTIVE AUDIO',className:'active-output',meta:`Job #${chapter.active_output_job_id}${plan}`}}if(chapter.audio_status==='completed')return {label:'HAS AUDIO',className:'done',meta:'Artifact active but job binding unavailable'};if(chapter.qa_count)return {label:`${chapter.qa_count} QA`,className:'',meta:''};return {label:'NOT RENDERED',className:'',meta:''}}
function chapterAudioMetaText(activeOutput){if(!activeOutput?.active_output_has_trustworthy_binding||!activeOutput?.active_output_job_id)return '';const plan=activeOutput.active_output_casting_plan_revision?` | Casting Plan v${activeOutput.active_output_casting_plan_revision}`:'';return `ACTIVE AUDIO | Job #${activeOutput.active_output_job_id}${plan}`}
async function loadChapters(){if(!state.book)return;const q=encodeURIComponent($('#chapterQuery').value.trim());const data=await api(`/api/books/${state.book.id}/chapters?offset=${state.page*state.pageSize}&limit=${state.pageSize}&query=${q}`);state.total=data.total;$('#chapterList').innerHTML=data.items.map(c=>{const status=chapterStatusSummary(c);return `<div class="chapter-row" data-id="${c.id}"><span class="chapter-number">${c.chapter_number}</span><span class="chapter-title-wrap"><span class="chapter-title">${esc(c.title)}</span>${status.meta?`<span class="chapter-title-meta">${esc(status.meta)}</span>`:''}</span><span class="status-dot ${status.className}">${status.label}</span></div>`}).join('');document.querySelectorAll('.chapter-row').forEach(el=>el.onclick=()=>openChapter(+el.dataset.id));$('#pageInfo').textContent=`${state.page*state.pageSize+1}-${Math.min((state.page+1)*state.pageSize,state.total)} / ${state.total}`;$('#prevPage').disabled=state.page===0;$('#nextPage').disabled=(state.page+1)*state.pageSize>=state.total}
async function openChapter(id){try{state.dialog=await api(`/api/chapters/${id}`);state.diffChapterId=null;state.diffRevisions=null;state.diffData=null;$('#dialogTitle').textContent=state.dialog.chapter.title;$('#qaIssues').innerHTML=state.dialog.qa_issues.slice(0,12).map(i=>`<div class="issue">${esc(i.message)}</div>`).join('');const box=$('#audioBox'),meta=$('#chapterAudioMeta');if(state.dialog.audio_artifact){const url=`/api/artifacts/${state.dialog.audio_artifact.id}/file`;box.classList.remove('hidden');$('#chapterAudio').src=url;$('#audioFileLink').href=url;const metaText=chapterAudioMetaText(state.dialog.active_output);meta.textContent=metaText;meta.classList.toggle('hidden',!metaText)}else{box.classList.add('hidden');$('#chapterAudio').removeAttribute('src');meta.textContent='';meta.classList.add('hidden')}showRevision('reflowed');$('#textDialog').showModal()}catch(e){toast(e.message,true)}}
function showRevision(kind){document.querySelectorAll('.tabs button').forEach(b=>b.classList.toggle('active',b.dataset.tab===kind));if(kind==='casting'){openCasting();return}if(kind==='diff'){openTextDiff();return}$('#castingPanel').classList.add('hidden');$('#textDiffPanel').classList.add('hidden');$('#chapterText').classList.remove('hidden');const rev=state.dialog?.revisions.find(r=>r.kind===kind)||state.dialog?.revisions.find(r=>r.kind==='reflowed');$('#chapterText').textContent=rev?.text||'Chưa có revision này.'}
async function loadPresetVoices(){const b=$('#loadPresetVoices');b.disabled=true;b.textContent='Loading…';try{const data=await api('/api/voices');state.voices=data.items;$('#presetVoiceSelect').innerHTML=data.items.map(v=>`<option value="${esc(v.id)}">${esc(v.label)}</option>`).join('');toast(`Loaded ${data.items.length} preset voices`);$('#previewPresetVoice').disabled=false}catch(e){toast(e.message,true)}finally{b.disabled=false;b.textContent='Load Preset Voices'}}
async function previewPresetVoice(){const voiceId=$('#presetVoiceSelect').value;if(!voiceId)return;const button=$('#previewPresetVoice');button.disabled=true;button.textContent='Creating preview…';try{const result=await api('/api/voice-previews',{method:'POST',body:JSON.stringify({voice_id:voiceId})});const audio=$('#presetPreviewAudio');audio.src=`${result.audio_url}?v=${result.cache_key}`;$('#presetPreviewBox').classList.remove('hidden');$('#presetPreviewStatus').textContent=`${(result.duration_ms/1000).toFixed(1)} seconds · ${result.cache_hit?'cached':'generated'}`;await audio.play().catch(()=>{});}catch(e){toast(e.message,true)}finally{button.disabled=false;button.textContent='▶ Preview 10–20s'}}
async function loadVoices(){const b=$('#loadVoices');b.disabled=true;b.textContent='Đang tải model…';try{const data=await api('/api/voices');state.voices=data.items;await loadCustomVoices();$('#voiceSelect').innerHTML=castingVoiceOptions();const total=state.voices.length+(state.customVoices?.length||0);toast(`Đã tải ${total} giọng`);syncMutationControls()}catch(e){toast(e.message,true)}finally{b.disabled=false;b.textContent='Tải giọng'}}
