async function previewVoice(){const voiceId=$('#voiceSelect').value;if(!voiceId)return;const button=$('#previewVoice');button.disabled=true;button.textContent='Đang tạo preview…';try{const result=await api('/api/voice-previews',{method:'POST',body:JSON.stringify({voice_id:voiceId})});const audio=$('#voicePreviewAudio');audio.src=`${result.audio_url}?v=${result.cache_key}`;$('#voicePreviewBox').classList.remove('hidden');$('#voicePreviewStatus').textContent=`${(result.duration_ms/1000).toFixed(1)} giây · ${result.cache_hit?'dùng cache':'vừa tạo'}`;await audio.play().catch(()=>{});}catch(e){toast(e.message,true)}finally{button.disabled=!$('#voiceSelect').value;button.textContent='▶ Preview 10–20s'}}
async function preview(){if(!state.book)return;try{const f=+$('#fromChapter').value,t=+$('#toChapter').value;const p=await api(`/api/jobs/preview?book_id=${state.book.id}&from_chapter=${f}&to_chapter=${t}`);$('#preview').classList.remove('empty');$('#preview').innerHTML=`<strong>${p.total} chương</strong> · ${p.completed} đã có audio · ${p.pending} cần tạo<br><span class="muted">${p.characters.toLocaleString('vi-VN')} ký tự · khoảng ${p.estimated_audio_minutes} phút audio · ${p.estimated_processing_minutes} phút xử lý</span>`;state.previewOk=true;syncMutationControls()}catch(e){state.previewOk=false;syncMutationControls();toast(e.message,true)}}
async function runJob(){if(!runtimeAllowsMutation()){toast('Runtime identity must be resolved before mutating actions.',true);return}if(!state.previewOk||!state.book)return;const payload={book_id:state.book.id,from_chapter:+$('#fromChapter').value,to_chapter:+$('#toChapter').value,voice_name:$('#voiceSelect').value,repair_mode:$('#repairMode').value,output_format:$('#outputFormat').value,skip_completed:$('#skipCompleted').checked};try{const r=await api('/api/jobs',{method:'POST',body:JSON.stringify(payload)});toast(`Đã tạo job #${r.job_id}. Có ${state.config.undo_seconds} giây để hoàn tác.`);state.previewOk=false;syncMutationControls();await loadJobs()}catch(e){toast(e.message,true)}}
async function act(id,action){if(!runtimeAllowsMutation()){toast('Runtime identity must be resolved before mutating actions.',true);return}try{await api(`/api/jobs/${id}/${action}`,{method:'POST',body:'{}'});toast(`Đã gửi yêu cầu ${action}`);loadJobs()}catch(e){toast(e.message,true)}}window.act=act;
function castingVoiceOptions(selected=''){const voices=state.voices||[],customs=state.customVoices||[];const presetMatch=voices.some(v=>v.id===selected),customMatch=customs.some(v=>`custom:${v.id}`===selected),known=presetMatch||customMatch;let html='';if(!known&&selected)html+=`<option value="${esc(selected)}" selected disabled>[Missing] ${esc(selected)}</option>`;if(voices.length>0){html+='<optgroup label="Preset Voices">';html+=voices.map(v=>`<option value="${esc(v.id)}" ${v.id===selected?'selected':''}>${esc(v.label)}</option>`).join('');html+='</optgroup>'}if(customs.length>0){html+='<optgroup label="Custom Voices">';html+=customs.map(v=>{const value=`custom:${v.id}`;return `<option value="${esc(value)}" ${value===selected?'selected':''}>${esc(v.display_name)} (Custom)</option>`}).join('');html+='</optgroup>'}return html}
const sourceLabels={character_override:'Character override',narrator:'Book narrator default',book_male:'Book male default',book_female:'Book female default',unknown_fallback:'Unknown fallback',legacy_snapshot:'Legacy snapshot',custom_reference:'Custom voice'};
function resolutionText(r){if(!r)return 'No effective voice — create a Book Voice Profile.';let voiceLabel=r.resolved_voice_id;if(voiceLabel&&voiceLabel.startsWith('custom:')){const customId=voiceLabel.substring(7);const custom=state.customVoices?.find(v=>v.id===+customId);if(custom)voiceLabel=`${custom.display_name} (Custom)`;else voiceLabel=`Custom voice #${customId}`}return `Effective voice: ${voiceLabel} · Resolved from: ${sourceLabels[r.resolution_source]||r.resolution_source}${r.needs_review?' · Needs review':''}`}
function renderVoiceProfile(){const vp=state.casting.voice_profile||{},p=vp.profile,first=state.voices?.[0]?.id||'';$('#voiceProfileEmpty').classList.toggle('hidden',!!p);$('#voiceProfileMeta').textContent=p?`Profile v${p.config_version} · ${new Date(p.updated_at).toLocaleString('vi-VN')}`:'Not configured';$('#profileNarratorVoice').innerHTML=castingVoiceOptions(p?.narrator_voice_id||first);$('#profileMaleVoice').innerHTML=castingVoiceOptions(p?.male_dialogue_voice_id||first);$('#profileFemaleVoice').innerHTML=castingVoiceOptions(p?.female_dialogue_voice_id||first);$('#profileExplicitVoice').innerHTML=castingVoiceOptions(p?.unknown_voice_id||first);$('#profileUnknownFallback').value=p?.unknown_fallback||'narrator';profileFallbackChanged();const validation=vp.validation;$('#profileValidation').textContent=validation&&!validation.valid?`Missing preset: ${validation.missing_preset_ids.join(', ')}. Update the profile before creating a new casting plan.`:p?'Profile is valid.':'';$('#profileValidation').classList.toggle('error-text',!!validation&&!validation.valid);$('#saveVoiceProfile').textContent=p?'Save Voice Profile':'Create Voice Profile';document.querySelectorAll('[data-profile-preview]').forEach(b=>b.disabled=!profilePreviewVoiceId(b.dataset.profilePreview)||!!(validation&&!validation.valid))}
function profileFallbackChanged(){const explicit=$('#profileUnknownFallback').value==='explicit_voice';$('#profileExplicitVoiceLabel').classList.toggle('hidden',!explicit)}
function profilePreviewVoiceId(slot){if(slot==='narrator')return $('#profileNarratorVoice').value;if(slot==='male')return $('#profileMaleVoice').value;if(slot==='female')return $('#profileFemaleVoice').value;const policy=$('#profileUnknownFallback').value;return policy==='narrator'?$('#profileNarratorVoice').value:policy==='male_dialogue'?$('#profileMaleVoice').value:policy==='female_dialogue'?$('#profileFemaleVoice').value:$('#profileExplicitVoice').value}
async function previewProfileVoice(slot){const voiceId=profilePreviewVoiceId(slot);if(!voiceId)return;const button=document.querySelector(`[data-profile-preview="${slot}"]`);button.disabled=true;try{const result=await api('/api/voice-previews',{method:'POST',body:JSON.stringify({voice_id:voiceId})});const audio=$('#profilePreviewAudio');audio.src=`${result.audio_url}?v=${result.cache_key}`;$('#profilePreviewBox').classList.remove('hidden');$('#profilePreviewStatus').textContent=`${voiceId} · ${(result.duration_ms/1000).toFixed(1)} giây · ${result.cache_hit?'dùng cache':'vừa tạo'}`;await audio.play().catch(()=>{})}catch(e){toast(e.message,true)}finally{button.disabled=false}}
async function saveVoiceProfile(){if(!runtimeAllowsMutation()){toast('Runtime identity must be resolved before mutating actions.',true);return}const fallback=$('#profileUnknownFallback').value,payload={narrator_voice_id:$('#profileNarratorVoice').value,male_dialogue_voice_id:$('#profileMaleVoice').value,female_dialogue_voice_id:$('#profileFemaleVoice').value,unknown_fallback:fallback,unknown_voice_id:fallback==='explicit_voice'?$('#profileExplicitVoice').value:null};try{await api(`/api/books/${state.casting.chapter.book_id}/voice-profile`,{method:'PUT',body:JSON.stringify(payload)});toast('Đã lưu Book Voice Profile. Thay đổi chỉ áp dụng cho casting plan và job mới.');await openCasting()}catch(e){toast(e.message,true)}}
async function openCasting(){try{if(!state.voices?.length)await loadVoices();if(!state.customVoices?.length)await loadCustomVoices();const chapterId=state.dialog.chapter.id,preferred=state.speakerReview?.chapterId===chapterId?state.speakerReview.draft?.id:null;state.casting=await api(`/api/chapters/${chapterId}/casting`);if(state.speakerReview?.chapterId!==chapterId)state.speakerReview={chapterId,drafts:[],draft:null,decisions:{},selected:{},generation:null};$('#chapterText').classList.add('hidden');$('#textDiffPanel').classList.add('hidden');$('#castingPanel').classList.remove('hidden');renderCasting();await loadSpeakerDrafts(preferred)}catch(e){toast(e.message,true)}}

function speakerName(type,characterId){if(type==='narrator')return 'Narrator';if(type==='unknown')return 'Unknown';const c=(state.speakerReview?.draft?.characters||state.casting?.characters||[]).find(item=>item.id===characterId);return c?c.display_name:`Character #${characterId}`}
function reviewedDecisionCount(review){return Object.keys(review?.decisions||{}).length}
function localRemainingUnreviewedCount(review){const draft=review?.draft;if(!draft)return 0;const pending=Object.values(review?.decisions||{}).filter(item=>!draft.review_rows.find(row=>row.utterance_id===item.utterance_id)?.reviewed).length;return Math.max(0,(draft.remaining_unreviewed_count??0)-pending)}
function setReviewSelection(utteranceId,checked){const review=state.speakerReview;if(!review)return;if(!review.selected)review.selected={};if(checked)review.selected[utteranceId]=true;else delete review.selected[utteranceId];updateSpeakerReviewApproval()}
function selectVisibleReviewRows(){const review=state.speakerReview;if(!review?.draft)return;if(!review.selected)review.selected={};review.draft.review_rows.filter(reviewFilterMatch).forEach(row=>{review.selected[row.utterance_id]=true});renderSpeakerReview()}
function clearSelectedReviewRows(){const review=state.speakerReview;if(!review)return;review.selected={};renderSpeakerReview()}
function reviewDecision(row,value){const suggestion=row.suggestion;if(value==='suggestion'&&suggestion)return {utterance_id:row.utterance_id,speaker_type:suggestion.speaker_type,character_id:suggestion.character_id,decision_source:'gemini_suggestion'};if(value.startsWith('alternative:')&&suggestion){const alt=suggestion.alternatives?.[+value.split(':')[1]];if(alt)return {utterance_id:row.utterance_id,speaker_type:alt.speaker_type,character_id:alt.character_id,decision_source:'gemini_alternative'}}if(value==='narrator')return {utterance_id:row.utterance_id,speaker_type:'narrator',character_id:null,decision_source:'narrator'};if(value==='unknown')return {utterance_id:row.utterance_id,speaker_type:'unknown',character_id:null,decision_source:'unknown'};if(value==='current'&&row.current_assignment)return {utterance_id:row.utterance_id,...row.current_assignment,decision_source:'keep_current'};if(value.startsWith('character:'))return {utterance_id:row.utterance_id,speaker_type:'character',character_id:+value.split(':')[1],decision_source:'manual_character'};return null}
function reviewChoiceValue(row,decision){if(!decision)return 'skip';if(decision.decision_source==='gemini_suggestion')return 'suggestion';if(decision.decision_source==='gemini_alternative'){const index=row.suggestion?.alternatives?.findIndex(item=>item.speaker_type===decision.speaker_type&&item.character_id===decision.character_id);return index>=0?`alternative:${index}`:'skip'}if(decision.decision_source==='keep_current')return 'current';if(decision.decision_source==='manual_character')return `character:${decision.character_id}`;return decision.speaker_type}
function reviewFilterMatch(row){const filter=$('#speakerReviewFilter').value,decision=state.speakerReview.decisions[row.utterance_id],level=row.invalid_item?'invalid':row.suggestion?.confidence_level;if(filter==='all')return true;if(filter==='unreviewed')return !row.reviewed&&!decision;if(filter==='invalid')return !!row.invalid_item;if(filter==='needs_review')return !!row.suggestion?.needs_review||!!row.invalid_item;return level===filter}
function reviewRowElement(row){const s=row.suggestion,level=row.invalid_item?'invalid':s?.confidence_level||'invalid',current=row.current_assignment?speakerName(row.current_assignment.speaker_type,row.current_assignment.character_id):'None',suggestion=s?speakerName(s.speaker_type,s.character_id):'Unavailable',reason=s?.reason||row.invalid_item?.error_code||'No reason provided.',alternatives=(s?.alternatives||[]).map(item=>`${speakerName(item.speaker_type,item.character_id)} ${Math.round(item.confidence*100)}%`).join(' · ')||'None',root=document.createElement('div');root.className=`speaker-review-row${reviewFilterMatch(row)?'':' hidden-filter'}`;root.dataset.reviewRow=row.utterance_id;const check=document.createElement('input');check.className='review-check';check.type='checkbox';check.dataset.reviewCheck=row.utterance_id;check.checked=!!state.speakerReview.selected?.[row.utterance_id];check.onchange=()=>setReviewSelection(row.utterance_id,check.checked);const seq=document.createElement('span');seq.className='utterance-seq';seq.textContent=row.sequence;const textBox=document.createElement('div'),id=document.createElement('strong'),text=document.createElement('p'),currentText=document.createElement('small');id.textContent=row.utterance_id;text.className='speaker-review-text';text.textContent=row.text;currentText.textContent=`Current: ${current}`;textBox.append(id,text,currentText);const suggestionBox=document.createElement('div'),suggestionName=document.createElement('strong'),confidence=document.createElement('span'),reasonText=document.createElement('span'),alternativesText=document.createElement('small');suggestionBox.className='speaker-review-suggestion';suggestionName.textContent=suggestion;confidence.className=`confidence-${level}`;confidence.textContent=`${level.toUpperCase()}${s?` · ${Math.round(s.confidence*100)}%`:''}`;reasonText.textContent=reason;alternativesText.textContent=`Alternatives: ${alternatives}`;suggestionBox.append(suggestionName,confidence,reasonText,alternativesText);const decisionBox=document.createElement('div'),label=document.createElement('label'),select=document.createElement('select'),preview=document.createElement('button'),voice=document.createElement('span');decisionBox.className='speaker-review-decision';label.append('Review decision');select.dataset.reviewChoice=row.utterance_id;const selected=reviewChoiceValue(row,state.speakerReview.decisions[row.utterance_id]),choices=[['skip','Skip for now']];if(s)choices.push(['suggestion',`Use suggestion: ${speakerName(s.speaker_type,s.character_id)}`]);(s?.alternatives||[]).forEach((item,index)=>choices.push([`alternative:${index}`,`Alternative: ${speakerName(item.speaker_type,item.character_id)} (${Math.round(item.confidence*100)}%)`]));choices.push(['narrator','Narrator'],['unknown','Unknown']);if(row.current_assignment)choices.push(['current',`Keep current: ${current}`]);(state.speakerReview.draft.characters||[]).forEach(c=>choices.push([`character:${c.id}`,`Character: ${c.display_name}`]));choices.forEach(([value,name])=>select.add(new Option(name,value,false,value===selected)));select.onchange=()=>setSpeakerReviewChoice(row.utterance_id,select.value);label.append(select);preview.className='ghost';preview.textContent='Preview effective voice';preview.onclick=()=>previewReviewVoice(row.utterance_id);voice.id=`review-voice-${row.utterance_id}`;voice.className='review-voice-result';decisionBox.append(label,preview,voice);const details=document.createElement('details'),summary=document.createElement('summary'),contextList=document.createElement('div');details.className='speaker-context';summary.textContent='Context';contextList.className='speaker-context-list';(row.context||[]).forEach(item=>{const context=document.createElement('div');context.className=`speaker-context-item${item.is_target?' target':''}`;context.textContent=item.text;if(item.confirmed_assignment){const known=document.createElement('small');known.textContent=` · ${speakerName(item.confirmed_assignment.speaker_type,item.confirmed_assignment.character_id)}`;context.append(known)}contextList.append(context)});details.append(summary,contextList);root.append(check,seq,textBox,suggestionBox,decisionBox,details);return root}
function renderSpeakerReview(){const review=state.speakerReview||{},draft=review.draft,items=review.drafts||[];$('#speakerDraftSelect').innerHTML=items.length?items.map(item=>`<option value="${item.id}" ${draft?.id===item.id?'selected':''}>Draft #${item.id}${item.stale?' · Outdated':''} · ${esc(item.status||'invalid')}</option>`).join(''):'<option value="">No drafts</option>';$('#speakerReviewEmpty').classList.toggle('hidden',items.length>0);$('#speakerReviewWorkspace').classList.toggle('hidden',!draft);$('#regenerateSpeakerDraft').disabled=!runtimeAllowsMutation()||!draft||review.busy;$('#generateSpeakerDraft').disabled=!runtimeAllowsMutation()||!!review.busy;$('#refreshSpeakerDrafts').disabled=!!review.busy;if(!draft){$('#speakerReviewStatus').textContent='No draft';$('#speakerReviewMeta').innerHTML='';$('#speakerReviewRows').replaceChildren();$('#speakerReviewStale').classList.add('hidden');return}$('#speakerReviewStatus').textContent=draft.stale?'Outdated draft':`${draft.status} · ${localRemainingUnreviewedCount(review)} remaining`;const counts={high:0,medium:0,low:0,invalid:0};draft.review_rows.forEach(row=>{counts[row.invalid_item?'invalid':row.suggestion?.confidence_level||'invalid']++});$('#speakerReviewMeta').innerHTML=`<div><strong>#${draft.id}</strong><span>Draft</span></div><div><strong>${esc(draft.model_id)}</strong><span>${esc(draft.prompt_version)}</span></div><div><strong>${draft.target_count} / ${draft.valid_count} / ${draft.invalid_count}</strong><span>Target / valid / invalid</span></div><div><strong>${counts.high} / ${counts.medium} / ${counts.low} / ${counts.invalid}</strong><span>High / medium / low / invalid</span></div><div><strong>${esc(draft.input_fingerprint.slice(0,12))}</strong><span>Input fingerprint</span></div><div><strong>#${draft.text_revision_id}</strong><span>Text revision</span></div>${review.generation?`<div><strong>${review.generation.reused?'Reused':'Generated'}</strong><span>Cache ${review.generation.cache?.hit_count||0} hit / ${review.generation.cache?.miss_count||0} miss</span></div>`:''}`;$('#speakerReviewStale').textContent=(draft.stale_reasons||[]).join(' ');$('#speakerReviewStale').classList.toggle('hidden',!draft.stale);const rows=draft.review_rows.map(reviewRowElement);if(rows.length)$('#speakerReviewRows').replaceChildren(...rows);else{const empty=document.createElement('p');empty.className='muted';empty.textContent='This draft has no reviewable targets.';$('#speakerReviewRows').replaceChildren(empty)}updateSpeakerReviewApproval()}
async function loadSpeakerDrafts(preferredId=null){const review=state.speakerReview;review.busy=true;renderSpeakerReview();try{const data=await api(`/api/chapters/${review.chapterId}/speaker-assignment/drafts`);review.drafts=data.items;const usable=data.items.find(item=>item.id===+preferredId)||data.items.find(item=>!item.stale&&!item.load_error)||data.items[0];if(usable&&!usable.load_error){review.draft=await api(`/api/chapters/${review.chapterId}/speaker-assignment/drafts/${usable.id}`);review.decisions={};review.selected={}}else review.draft=null}finally{review.busy=false;renderSpeakerReview()}}
async function openSpeakerDraft(id){if(!id)return;try{state.speakerReview.draft=await api(`/api/chapters/${state.speakerReview.chapterId}/speaker-assignment/drafts/${id}`);state.speakerReview.decisions={};state.speakerReview.selected={};renderSpeakerReview()}catch(e){toast(e.message,true)}}
async function generateSpeakerDraft(force=false){if(!runtimeAllowsMutation()){toast('Runtime identity must be resolved before mutating actions.',true);return}const review=state.speakerReview;review.busy=true;renderSpeakerReview();try{const mode=force?'reanalyze':'unassigned_only',result=await api(`/api/chapters/${review.chapterId}/speaker-assignment/draft`,{method:'POST',body:JSON.stringify({mode,utterance_ids:null,force_refresh:force})});review.generation={reused:!!result.reused,cache:result.cache};toast(`Draft #${result.id} ${result.reused?'reused':'generated'} · cache ${result.cache?.hit_count||0} hit`);await loadSpeakerDrafts(result.id)}catch(e){toast(e.message,true)}finally{review.busy=false;renderSpeakerReview()}}
function setSpeakerReviewChoice(utteranceId,value){const row=state.speakerReview.draft.review_rows.find(item=>item.utterance_id===utteranceId),decision=row?reviewDecision(row,value):null;if(decision)state.speakerReview.decisions[utteranceId]=decision;else delete state.speakerReview.decisions[utteranceId];updateSpeakerReviewApproval()}
function updateSpeakerReviewApproval(){const review=state.speakerReview,draft=review?.draft,count=reviewedDecisionCount(review);$('#speakerReviewDecisionCount').textContent=`${count} reviewed · ${localRemainingUnreviewedCount(review)} remaining`;$('#approveSpeakerReview').disabled=!runtimeAllowsMutation()||!draft||draft.stale||count===0||review.busy;document.querySelectorAll('[data-review-row]').forEach(el=>{const row=draft.review_rows.find(item=>item.utterance_id===el.dataset.reviewRow);el.classList.toggle('hidden-filter',!reviewFilterMatch(row))})}
function selectedReviewRows(){return Object.keys(state.speakerReview?.selected||{}).filter(utteranceId=>state.speakerReview.selected[utteranceId]).map(utteranceId=>state.speakerReview.draft.review_rows.find(row=>row.utterance_id===utteranceId)).filter(Boolean)}
function bulkReview(action){const rows=selectedReviewRows();rows.forEach(row=>{let value='skip';if(action==='suggestion'&&row.suggestion)value='suggestion';if(action==='narrator')value='narrator';if(action==='unknown')value='unknown';setSpeakerReviewChoice(row.utterance_id,value)});renderSpeakerReview()}
async function previewReviewVoice(utteranceId){const decision=state.speakerReview.decisions[utteranceId],target=$(`#review-voice-${CSS.escape(utteranceId)}`);if(!decision){target.textContent='Choose a review decision first.';return}try{const result=await api(`/api/books/${state.casting.chapter.book_id}/voice-profile/resolve`,{method:'POST',body:JSON.stringify({speaker_type:decision.speaker_type==='narrator'?'narrator':'dialogue',character_id:decision.character_id})});target.textContent=`${result.resolved_voice_id} · ${sourceLabels[result.resolution_source]||result.resolution_source} · ${result.gender}${result.needs_review?' · Needs review':''}`}catch(e){target.textContent=e.message}}
async function reviewIdempotencyKey(draft,decisions){const stable=JSON.stringify([...decisions].sort((a,b)=>a.utterance_id.localeCompare(b.utterance_id))),bytes=new TextEncoder().encode(stable),digest=await crypto.subtle.digest('SHA-256',bytes);return `review-${draft.id}-${[...new Uint8Array(digest)].map(value=>value.toString(16).padStart(2,'0')).join('').slice(0,32)}`}
async function approveSpeakerReview(){if(!runtimeAllowsMutation()){toast('Runtime identity must be resolved before mutating actions.',true);return}const review=state.speakerReview,draft=review.draft,decisions=Object.values(review.decisions);if(!draft||!decisions.length||draft.stale)return;review.busy=true;updateSpeakerReviewApproval();try{const idempotency_key=await reviewIdempotencyKey(draft,decisions),result=await api(`/api/chapters/${review.chapterId}/speaker-assignment/drafts/${draft.id}/approve`,{method:'POST',body:JSON.stringify({base_casting_plan_revision_id:draft.base_casting_plan_id,expected_draft_fingerprint:draft.input_fingerprint,expected_text_revision_id:draft.text_revision_id,decisions,idempotency_key})});toast(`Casting Plan v${result.casting_plan_revision} created · ${result.approved_item_count} approved · ${result.remaining_unreviewed_count} remaining${result.idempotent_reused?' · reused':''}`);review.decisions={};await openCasting()}catch(e){toast(e.message,true)}finally{review.busy=false;updateSpeakerReviewApproval()}}
function utteranceResolution(u){if(u.resolution_source)return {resolved_voice_id:u.resolved_voice_id,resolution_source:u.resolution_source,gender:u.resolved_gender,needs_review:u.needs_review};if(u.role==='character')return state.casting.characters.find(c=>c.id===u.character_id)?.effective_resolution||null;if(u.role==='unknown')return state.casting.voice_profile?.unknown_resolution||null;return state.casting.voice_profile?.narrator_resolution||null}
function optionSet(values,selected){return values.map(v=>`<option value="${esc(v)}" ${v===selected?'selected':''}>${esc(v||'none')}</option>`).join('')}
function characterAliases(c){return (c.aliases||[]).length?`<div class="alias-list">${c.aliases.map(a=>`<span class="alias-chip" title="${esc(a)}">${esc(a)}</span>`).join('')}</div>`:'<div class="muted small">No aliases</div>'}
function characterAdvanced(c){return `<details class="character-advanced"><summary>Import provenance</summary>${c.bible_schema?`<div class="metadata-grid compact"><label>Source schema<input value="${esc(c.bible_schema||'')}" disabled></label><label>Source label<input value="${esc(c.bible_source_label||'')}" disabled></label><label>Imported at<input value="${esc(c.bible_imported_at||'')}" disabled></label><label>Last imported<input value="${esc(c.bible_last_imported_at||'')}" disabled></label></div>`:'<p class="muted">No Character Bible provenance.</p>'}</details>`}
function renderCharacterRow(c){const custom=!!c.voice_override_id;return `<div class="character-row character-card"><div class="identity-fields"><label>Canonical name<input id="character-name-${c.id}" value="${esc(c.display_name)}"></label><label>External key<input value="${esc(c.external_key||'')}" disabled></label>${characterAliases(c)}</div><div class="metadata-grid"><label>Gender<select id="character-gender-${c.id}" onchange="refreshCharacterEffective(${c.id})"><option value="unknown" ${(c.gender||'unknown')==='unknown'?'selected':''}>Unknown</option><option value="male" ${c.gender==='male'?'selected':''}>Male</option><option value="female" ${c.gender==='female'?'selected':''}>Female</option></select></label><label>Role<select id="character-role-${c.id}">${optionSet(['unknown','main','supporting','minor'],c.role||'unknown')}</select></label><label>Age group<select id="character-age-${c.id}">${optionSet(['','unknown','child','teen','young_adult','adult','elder'],c.age_group||'')}</select></label><label>Voice assignment<select id="character-assignment-${c.id}" onchange="toggleCharacterVoice(${c.id})"><option value="default" ${custom?'':'selected'}>Use book default</option><option value="custom" ${custom?'selected':''}>Use custom voice</option></select></label><select id="character-voice-${c.id}" class="${custom?'':'hidden'}" onchange="refreshCharacterEffective(${c.id})">${castingVoiceOptions(c.voice_override_id||'')}</select><div id="character-effective-${c.id}" class="effective-voice ${c.effective_resolution?.needs_review?'needs-review':''}">${esc(resolutionText(c.effective_resolution))}</div></div><div class="metadata-text"><label>Description<textarea id="character-description-${c.id}" rows="2">${esc(c.description||'')}</textarea></label><label>Speech style<textarea id="character-speech-${c.id}" rows="2">${esc(c.speech_style||'')}</textarea></label><label>Visual notes<textarea id="character-visual-${c.id}" rows="2">${esc(c.visual_notes||'')}</textarea></label><label>General notes<textarea id="character-notes-${c.id}" rows="2">${esc(c.notes||'')}</textarea></label></div>${characterAdvanced(c)}<div class="character-actions"><button onclick="saveCharacter(${c.id})">Lưu</button><button onclick="deleteCharacter(${c.id})">Xóa</button></div></div>`}
function bibleSummary(summary){if(!summary)return '';const items=[['Total','characters_total'],['Create','create_count'],['Match','match_count'],['Update','update_count'],['Aliases','alias_add_count'],['Conflict','conflict_count'],['Invalid','invalid_count'],['Warnings','warning_count']];return `<div class="import-summary-grid">${items.map(([label,key])=>`<div><strong>${summary[key]||0}</strong><span>${label}</span></div>`).join('')}</div>`}
function renderBiblePlan(plan){if(!plan)return '';return plan.records.map(item=>`<div class="import-record ${esc(item.action)}"><div><strong>${esc(item.canonical_name||'Invalid record')}</strong><span>${esc(item.external_key||'')}</span></div><span class="badge ${esc(item.action)}">${esc(item.action)}</span>${item.character_id?`<span class="muted">Matched #${item.character_id}</span>`:''}${Object.keys(item.changes||{}).length?`<details><summary>Fields to change</summary><ul>${Object.entries(item.changes).map(([k,v])=>`<li><code>${esc(k)}</code>: ${esc(v??'null')}</li>`).join('')}</ul></details>`:''}${(item.aliases_to_add||[]).length?`<div class="alias-list">${item.aliases_to_add.map(a=>`<span class="alias-chip">${esc(a)}</span>`).join('')}</div>`:''}${(item.warnings||[]).map(w=>`<div class="issue warning">${esc(w)}</div>`).join('')}${(item.errors||[]).map(e=>`<div class="issue error">${esc(e)}</div>`).join('')}</div>`).join('')}
function renderCharacterBibleImport(){const box=state.characterBible||{},file=box.file,plan=box.plan,summary=plan?.summary,blocked=!!summary&&(summary.conflict_count>0||summary.invalid_count>0);$('#characterBibleState').textContent=box.status||'No file selected';$('#characterBibleFileInfo').textContent=file?`${file.name} · ${bytes(file.size)}`:'No file selected.';$('#characterBibleDryRun').disabled=!box.payload||box.busy;$('#characterBibleApply').disabled=!plan||blocked||box.busy;$('#characterBibleClear').disabled=!file&&!plan&&!box.error;$('#characterBibleSummary').innerHTML=bibleSummary(summary)+(blocked?'<div class="issue error">Fix conflicts or invalid records, then run dry-run again.</div>':'');$('#characterBiblePlan').innerHTML=box.error?`<div class="issue error">${esc(box.error)}</div>`:renderBiblePlan(plan)}
async function selectCharacterBibleFile(){const file=$('#characterBibleFile').files?.[0];state.characterBible={file,status:file?'File selected':'No file selected'};if(!file){renderCharacterBibleImport();return}if(!file.name.toLowerCase().endsWith('.json'))state.characterBible.error='Please select a .json file.';else if(file.size<=0)state.characterBible.error='File is empty.';else if(file.size>2*1024*1024)state.characterBible.error='File is larger than 2 MiB.';else{try{state.characterBible.payload=JSON.parse(await file.text())}catch(e){state.characterBible.error=`Malformed JSON: ${e.message}`}}renderCharacterBibleImport()}
async function dryRunCharacterBible(){const box=state.characterBible;if(!box?.payload)return;box.busy=true;box.status='Validating';box.error='';renderCharacterBibleImport();try{box.plan=await api(`/api/books/${state.casting.chapter.book_id}/character-bible/dry-run`,{method:'POST',body:JSON.stringify({payload:box.payload,source_label:box.file?.name||'character_bible.json',update_existing:$('#characterBibleUpdateExisting').checked})});box.status=box.plan.summary.conflict_count||box.plan.summary.invalid_count?'Conflicts found':'Ready to apply'}catch(e){box.status='Import failed';box.error=e.message}finally{box.busy=false;renderCharacterBibleImport()}}
async function applyCharacterBibleUi(){const box=state.characterBible;if(!box?.payload)return;box.busy=true;box.status='Applying';renderCharacterBibleImport();try{const result=await api(`/api/books/${state.casting.chapter.book_id}/character-bible/apply`,{method:'POST',body:JSON.stringify({payload:box.payload,source_label:box.file?.name||'character_bible.json',update_existing:$('#characterBibleUpdateExisting').checked})});box.plan=result.plan;box.result=result.result;box.status='Import complete';toast(`Character Bible import complete: ${result.result.changed_records} changed record(s).`);await openCasting()}catch(e){box.status='Import failed';box.error=e.message;renderCharacterBibleImport()}}
function clearCharacterBibleUi(){state.characterBible=null;$('#characterBibleFile').value='';renderCharacterBibleImport()}
function renderCasting(){const context=state.casting,casting=context.casting,plan=casting.plan,vp=context.voice_profile||{},p=vp.profile;renderVoiceProfile();renderCharacterBibleImport();$('#castingNarratorVoice').innerHTML=castingVoiceOptions(p?.narrator_voice_id||casting.narrator_voice_id||$('#voiceSelect').value);$('#castingNarratorVoice').disabled=!!p;$('#castingNarratorSource').textContent=p?'Resolved from Book narrator default':'Legacy manual narrator voice';$('#newCharacterVoice').innerHTML=castingVoiceOptions($('#castingNarratorVoice').value);$('#newCharacterVoice').classList.add('hidden');$('#castingPlanStatus').textContent=casting.id?`Plan v${casting.plan_revision} · ${casting.status}`:'Chưa có plan';$('#characterList').innerHTML=context.characters.map(renderCharacterRow).join('')||'<p class="muted">Chưa có nhân vật.</p>';const speakerOptions=u=>`<option value="narrator" ${u.role==='narrator'?'selected':''}>Narrator</option><option value="unknown" ${u.role==='unknown'?'selected':''}>Unknown</option>`+context.characters.map(c=>`<option value="character:${c.id}" ${u.character_id===c.id?'selected':''}>${esc(c.display_name)}</option>`).join('');$('#utteranceList').innerHTML=plan.utterances.map(u=>{const r=utteranceResolution(u);return `<div class="utterance-row"><span class="utterance-seq">${u.sequence}</span><div><select data-utterance="${esc(u.utterance_id)}" onchange="refreshUtteranceResolution(this)">${speakerOptions(u)}</select><small class="utterance-resolution ${r?.needs_review?'needs-review':''}">${esc(resolutionText(r))}${r?.gender?` · Gender: ${esc(r.gender)}`:''}</small></div><p>${esc(u.text||'')}</p></div>`}).join('');$('#utteranceCount').textContent=`${plan.utterances.length} utterance`;$('#saveCastingDraft').disabled=!p||!!(vp.validation&&!vp.validation.valid);$('#approveCastingPlan').disabled=!runtimeAllowsMutation()||!casting.id||casting.status!=='draft';$('#renderCastingPlan').disabled=!runtimeAllowsMutation()||!casting.id||casting.status!=='approved';renderSpeakerReview();syncMutationControls()}
function toggleCharacterVoice(id){$(`#character-voice-${id}`).classList.toggle('hidden',$(`#character-assignment-${id}`).value!=='custom');refreshCharacterEffective(id)}
async function refreshCharacterEffective(id){const custom=$(`#character-assignment-${id}`).value==='custom',payload={speaker_type:'dialogue',character_id:id,gender:$(`#character-gender-${id}`).value,use_character_override:custom,voice_override_id:custom?$(`#character-voice-${id}`).value:null};const target=$(`#character-effective-${id}`);try{const r=await api(`/api/books/${state.casting.chapter.book_id}/voice-profile/resolve`,{method:'POST',body:JSON.stringify(payload)});target.textContent=resolutionText(r);target.classList.toggle('needs-review',!!r.needs_review)}catch(e){target.textContent=e.message;target.classList.add('needs-review')}}
function refreshUtteranceResolution(select){const [role,id]=select.value.split(':'),profile=state.casting.voice_profile,r=role==='character'?state.casting.characters.find(c=>c.id===+id)?.effective_resolution:role==='unknown'?profile?.unknown_resolution:profile?.narrator_resolution;const el=select.parentElement.querySelector('.utterance-resolution');el.textContent=`${resolutionText(r)}${r?.gender?` · Gender: ${r.gender}`:''}`;el.classList.toggle('needs-review',!!r?.needs_review)}
async function addCharacter(){const custom=$('#newCharacterAssignment').value==='custom';try{await api(`/api/books/${state.casting.chapter.book_id}/characters`,{method:'POST',body:JSON.stringify({display_name:$('#newCharacterName').value,gender:$('#newCharacterGender').value,voice_override_id:custom?$('#newCharacterVoice').value:null})});$('#newCharacterName').value='';await openCasting()}catch(e){toast(e.message,true)}}
async function saveCharacter(id){const custom=$(`#character-assignment-${id}`).value==='custom';try{await api(`/api/characters/${id}`,{method:'PATCH',body:JSON.stringify({display_name:$(`#character-name-${id}`).value,gender:$(`#character-gender-${id}`).value,role:$(`#character-role-${id}`).value,age_group:$(`#character-age-${id}`).value||null,description:$(`#character-description-${id}`).value,speech_style:$(`#character-speech-${id}`).value,visual_notes:$(`#character-visual-${id}`).value,notes:$(`#character-notes-${id}`).value})});await api(`/api/characters/${id}/voice-override`,{method:'PUT',body:JSON.stringify({gender:$(`#character-gender-${id}`).value,voice_override_id:custom?$(`#character-voice-${id}`).value:null})});toast(custom?'Đã lưu metadata và custom voice override.':'Đã lưu metadata và chuyển sang book default.');await openCasting()}catch(e){toast(e.message,true)}}
async function deleteCharacter(id){try{await api(`/api/characters/${id}`,{method:'DELETE'});await openCasting()}catch(e){toast(e.message,true)}}
async function saveCastingDraft(){if(!runtimeAllowsMutation()){toast('Runtime identity must be resolved before mutating actions.',true);return}try{const assignments=[...document.querySelectorAll('[data-utterance]')].map(el=>{const [role,id]=el.value.split(':');return {utterance_id:el.dataset.utterance,role,character_id:role==='character'?+id:null}});await api(`/api/chapters/${state.dialog.chapter.id}/casting/draft`,{method:'POST',body:JSON.stringify({text_revision_id:state.casting.casting.text_revision_id,narrator_voice_id:$('#castingNarratorVoice').value,assignments})});toast('Đã lưu casting draft mới.');await openCasting()}catch(e){toast(e.message,true)}}
