async function renderCastingPlan(){if(!runtimeAllowsMutation()){toast('Runtime identity must be resolved before mutating actions.',true);return}const c=state.dialog.chapter,casting=state.casting.casting;try{const result=await api('/api/jobs',{method:'POST',body:JSON.stringify({book_id:c.book_id,from_chapter:c.chapter_number,to_chapter:c.chapter_number,voice_name:$('#castingNarratorVoice').value,repair_mode:'off',output_format:$('#outputFormat').value,skip_completed:false,casting_plan_id:casting.id})});toast(`Đã tạo multi-voice job #${result.job_id}`);$('#textDialog').close();await loadJobs()}catch(e){toast(e.message,true)}}
window.saveCharacter=saveCharacter;window.deleteCharacter=deleteCharacter;window.toggleCharacterVoice=toggleCharacterVoice;window.refreshCharacterEffective=refreshCharacterEffective;window.refreshUtteranceResolution=refreshUtteranceResolution;
function revisionLabel(r){return `${r.kind} · #${r.id} · ${r.char_count.toLocaleString('vi-VN')} ký tự · ${r.short_hash}`}
function latestRevision(kind){return [...(state.diffRevisions||[])].reverse().find(r=>r.kind===kind)}
function setDiffPreset(leftKind,rightKind){const left=latestRevision(leftKind),right=latestRevision(rightKind);if(!left||!right)return;$('#diffRevisionA').value=left.id;$('#diffRevisionB').value=right.id;loadTextDiff()}
async function openTextDiff(){try{$('#chapterText').classList.add('hidden');$('#castingPanel').classList.add('hidden');$('#textDiffPanel').classList.remove('hidden');if(state.diffChapterId===state.dialog.chapter.id&&state.diffRevisions){renderDiffSelectors();return}$('#diffContent').innerHTML='<p class="muted">Đang tải danh sách revision…</p>';const data=await api(`/api/chapters/${state.dialog.chapter.id}/revisions`);state.diffChapterId=state.dialog.chapter.id;state.diffRevisions=data.items;state.diffData=null;state.diffMode='inline';renderDiffSelectors();const preferred=latestRevision('reflowed')&&latestRevision('repaired')?['reflowed','repaired']:latestRevision('raw')&&latestRevision('reflowed')?['raw','reflowed']:null;if(preferred)setDiffPreset(...preferred);else $('#diffContent').innerHTML='<p class="muted">Chapter cần ít nhất hai revision để tạo diff.</p>'}catch(e){$('#diffContent').textContent=e.message;toast(e.message,true)}}
function renderDiffSelectors(){const options=(state.diffRevisions||[]).map(r=>`<option value="${r.id}">${esc(revisionLabel(r))}</option>`).join('');$('#diffRevisionA').innerHTML=options;$('#diffRevisionB').innerHTML=options;document.querySelectorAll('[data-diff-preset]').forEach(button=>{const [a,b]=button.dataset.diffPreset.split(',');const missing=[a,b].filter(kind=>!latestRevision(kind));button.disabled=missing.length>0;button.title=missing.length?`Thiếu revision: ${missing.join(', ')}`:''})}
async function loadTextDiff(){const a=+$('#diffRevisionA').value,b=+$('#diffRevisionB').value;if(!a||!b)return;$('#diffContent').innerHTML='<p class="muted">Đang tính diff…</p>';try{state.diffData=await api(`/api/chapters/${state.dialog.chapter.id}/diff?revision_a=${a}&revision_b=${b}`);renderTextDiff()}catch(e){state.diffData=null;$('#diffContent').innerHTML=`<div class="issue">${esc(e.message)}</div>`}}
function visibleDiffText(value,operation){if(operation.whitespace_only&&$('#diffShowWhitespace').checked)return esc(value.replace(/ /g,'·').replace(/\t/g,'→').replace(/\n/g,'↵\n'));return esc(value)}
function renderDiffOperation(operation,side){let value=side==='left'?operation.left:operation.right;if(!value)return '';if(operation.whitespace_only&&!$('#diffShowWhitespace').checked)return '';const isEqual=operation.status==='equal';if(isEqual&&!$('#diffShowUnchanged').checked&&value.length>220)value=`${value.slice(0,90)} … ${value.slice(-90)}`;let cls='diff-equal';if(side==='left'&&['delete','replace'].includes(operation.status))cls='diff-removed';if(side==='right'&&['insert','replace'].includes(operation.status))cls='diff-added';return `<span class="${cls}${operation.whitespace_only?' diff-whitespace':''}">${visibleDiffText(value,operation)}</span>`}
function renderInlineBlock(block){if(block.status==='equal'&&block.collapsed_by_default&&!$('#diffShowUnchanged').checked)return '<div class="diff-collapsed">… phần không đổi đã thu gọn …</div>';const body=block.operations.map(op=>{if(op.status==='equal')return renderDiffOperation(op,'right');return renderDiffOperation(op,'left')+renderDiffOperation(op,'right')}).join('');return `<div class="diff-block ${block.status}">${body}</div>`}
function renderSideBlock(block){if(block.status==='equal'&&block.collapsed_by_default&&!$('#diffShowUnchanged').checked)return '<div class="diff-collapsed">… phần không đổi đã thu gọn …</div>';const left=block.operations.map(op=>renderDiffOperation(op,'left')).join(''),right=block.operations.map(op=>renderDiffOperation(op,'right')).join('');return `<div class="diff-side-row ${block.status}"><div>${left}</div><div>${right}</div></div>`}
function renderTextDiff(){const d=state.diffData;if(!d)return;const s=d.summary,meta=r=>`<div><strong>${esc(r.kind)} #${r.id}</strong><span>${esc(r.created_at)} · parent ${r.parent_revision_id??'—'} · ${esc(r.processor_version)} · ${esc(r.short_hash)}</span><span>${esc(r.status)}${r.is_active?' · active':''}${r.is_raw_selected?' · raw selected':''}</span></div>`;$('#diffRevisionMeta').innerHTML=meta(d.revision_a)+meta(d.revision_b);$('#diffSummary').innerHTML=`<div><strong>${s.blocks_changed}</strong><span>block thay đổi</span></div><div><strong>+${s.tokens_added} / −${s.tokens_removed}</strong><span>lexical token</span></div><div><strong>${s.punctuation_changes}</strong><span>punctuation</span></div><div><strong>${(s.change_ratio*100).toFixed(2)}%</strong><span>tỷ lệ lexical change</span></div><div><strong>${s.characters_a.toLocaleString('vi-VN')}</strong><span>ký tự A</span></div><div><strong>${s.characters_b.toLocaleString('vi-VN')}</strong><span>ký tự B</span></div>`;$('#diffWarnings').innerHTML=[...d.warnings,...(!s.lexical_integrity&&s.lexical_reason?[s.lexical_reason]:[])].map(w=>`<div class="issue">${esc(w)}</div>`).join('');$('#diffInlineMode').classList.toggle('active',state.diffMode!=='side');$('#diffSideMode').classList.toggle('active',state.diffMode==='side');$('#diffContent').className=`diff-content ${state.diffMode==='side'?'side':''}`;$('#diffContent').innerHTML=d.blocks.map(block=>state.diffMode==='side'?renderSideBlock(block):renderInlineBlock(block)).join('')||'<p class="muted">Hai revision trống.</p>'}
function bytes(n){if(n===null||n===undefined)return '—';if(n<1024)return `${n} B`;if(n<1048576)return `${(n/1024).toFixed(1)} KB`;return `${(n/1048576).toFixed(1)} MB`}
function statusBadge(status){return `<span class="badge ${esc(status)}">${esc(fmtStatus(status))}</span>`}
function fileState(item){if(!item.file_exists)return '<span class="diag-bad">Thiếu file</span>';if(item.hash_matches===false)return '<span class="diag-bad">Sai hash</span>';return '<span class="diag-good">Hợp lệ</span>'}

async function loadJobs(){try{const jobs=await api('/api/jobs');const mutationAttr=runtimeAllowsMutation()?'':' data-runtime-mutation-control disabled title="Resolve runtime identity before mutating jobs"';$('#jobs').innerHTML=jobs.map(j=>{const done=j.actual_completed||0,total=j.total_chapters||0,pct=total?Math.round(done*100/total):100,badge=outputBadge(j),meta=jobOutputMeta(j);return `<div class="job-card"><div class="job-top"><div><div class="job-title">#${j.id} ? ${esc(j.book_title)} ? Ch??ng ${j.from_chapter}?${j.to_chapter}</div><div class="job-meta">${esc(j.voice_name)} ? ${esc(j.repair_mode)} ? ${esc(j.output_format.toUpperCase())}${j.current_chapter_number?` ? hi?n t?i ch??ng ${j.current_chapter_number}`:''}</div>${meta?`<div class="job-output-meta">${esc(meta)}</div>`:''}</div><div>${statusBadge(j.status)}${badge}</div></div><div class="progress"><span style="width:${pct}%"></span></div><div class="job-meta">${done}/${total} ch??ng ? ${j.completed_segments||0}/${j.total_segments||0} segment${j.actual_failed?` ? ${j.actual_failed} l?i`:''}</div>${j.error_message?`<div class="issue">${esc(j.error_message)}</div>`:''}<div class="job-actions"><button onclick="openJobDiagnostics(${j.id})">Ch?n ?o?n</button>${['scheduled','queued','running','repairing','synthesizing','assembling'].includes(j.status)?`<button${mutationAttr} onclick="act(${j.id},'pause')">T?m d?ng</button><button${mutationAttr} onclick="act(${j.id},'cancel')">H?y</button>`:''}${j.status==='paused'?`<button${mutationAttr} onclick="act(${j.id},'resume')">Ti?p t?c</button><button${mutationAttr} onclick="act(${j.id},'cancel')">H?y</button>`:''}${['completed_with_errors','failed'].includes(j.status)?`<button${mutationAttr} onclick="act(${j.id},'retry')">Th? l?i ph?n l?i</button>`:''}</div></div>`}).join('')||'<p class="muted">Ch?a c? job.</p>';syncMutationControls()}catch(e){console.error(e)}}
async function openJobDiagnostics(id){try{const data=await api(`/api/diagnostics/jobs/${id}`);state.diagnosticJobId=id;$('#jobDiagnosticTitle').textContent=`Job #${id} ? ${data.job.book_title}`;const counts=Object.entries(data.summary.chapter_status_counts).map(([s,n])=>`<span>${statusBadge(s)} ${n}</span>`).join('');const banner=data.job.is_active_output?'<div class="diag-job-banner">ACTIVE CHAPTER OUTPUT</div>':data.job.is_historical_output?'<div class="diag-job-banner historical">HISTORICAL JOB ? not the current chapter output</div>':'';$('#jobDiagnosticBody').innerHTML=`${banner}<div class="diag-summary"><div><strong>${data.summary.chapter_total}</strong><span>ch??ng</span></div><div><strong>${data.summary.segment_verified}/${data.summary.segment_total}</strong><span>segment h?p l?</span></div><div><strong>${data.summary.segment_failed}</strong><span>segment l?i</span></div><div><strong>${data.summary.repair_failed}</strong><span>Gemini l?i</span></div></div><div class="diag-line">${statusBadge(data.job.status)} <span>${counts}</span></div>${data.job.error_message?`<div class="issue">${esc(data.job.error_message)}</div>`:''}<h3>Ch??ng</h3><div class="diag-table-wrap"><table class="diag-table"><thead><tr><th>Ch??ng</th><th>Tr?ng th?i</th><th>Gemini</th><th>Segment</th><th>Audio</th><th></th></tr></thead><tbody>${data.chapters.map(c=>`<tr><td>${c.chapter_number}. ${esc(c.title)}</td><td>${statusBadge(c.status)}${c.error_message?`<small>${esc(c.error_message)}</small>`:''}</td><td>${c.repair_failed}/${c.repair_total} l?i</td><td>${c.segment_verified}/${c.segment_total}${c.segment_failed?` ? ${c.segment_failed} l?i`:''}</td><td>${c.is_active_output?'ACTIVE AUDIO':c.artifact_active?'Historical':'?'}</td><td class="diag-actions"><button onclick="openChapterDiagnostics(${c.job_chapter_id})">Chi ti?t</button>${['failed','needs_review','cancelled','interrupted'].includes(c.status)?`<button onclick="retryChapter(${c.job_chapter_id})">Th? l?i</button>`:''}</td></tr>`).join('')}</tbody></table></div><details><summary>C?u h?nh snapshot</summary><pre class="diag-json">${esc(JSON.stringify(data.job.settings,null,2))}</pre></details><details><summary>Nh?t k? g?n ??y (${data.events.length})</summary><div class="event-list">${data.events.map(e=>`<div><code>${esc(e.event_code)}</code><span>${esc(e.created_at)}</span></div>`).join('')||'Ch?a c? s? ki?n.'}</div></details>`;$('#chapterDiagnosticsDialog').close();$('#segmentDiagnosticsDialog').close();if(!$('#jobDiagnosticsDialog').open)$('#jobDiagnosticsDialog').showModal()}catch(e){toast(e.message,true)}}
async function openChapterDiagnostics(id){try{const data=await api(`/api/diagnostics/job-chapters/${id}`);state.diagnosticChapterId=id;state.diagnosticJobId=data.chapter.job_id;$('#chapterDiagnosticTitle').textContent=`Ch??ng ${data.chapter.chapter_number} ? ${data.chapter.title}`;const rev=data.text_revision;$('#chapterDiagnosticBody').innerHTML=`<div class="diag-line">${statusBadge(data.chapter.status)}${rev?`<span>Revision #${rev.id} ? ${esc(rev.kind)} ? ${rev.char_count.toLocaleString('vi-VN')} k? t?</span>`:'<span>Ch?a g?n text revision</span>'}</div>${data.chapter.error_message?`<div class="issue">${esc(data.chapter.error_message)}</div>`:''}<h3>Gemini repair blocks (${data.repair_blocks.length})</h3>${data.repair_blocks.length?`<div class="diag-table-wrap"><table class="diag-table"><thead><tr><th>#</th><th>Tr?ng th?i</th><th>L?n th?</th><th>Source</th><th>Output</th><th>L?i</th></tr></thead><tbody>${data.repair_blocks.map(b=>`<tr><td>${b.block_index}</td><td>${statusBadge(b.status)}</td><td>${b.attempt_count}</td><td>${b.source_file_exists?'Co':'Thi?u'}</td><td>${b.repaired_file_exists?'Co':'?'}</td><td>${esc(b.error_message||'')}</td></tr>`).join('')}</tbody></table></div>`:'<p class="muted">Khong dung Gemini repair cho chuong nay.</p>'}<h3>Segments (${data.segments.length})</h3><div class="diag-table-wrap"><table class="diag-table"><thead><tr><th>#</th><th>Tr?ng th?i</th><th>Text</th><th>Audio</th><th>Th?i lu?ng</th><th></th></tr></thead><tbody>${data.segments.map(s=>`<tr><td>${s.segment_index}</td><td>${statusBadge(s.status)}${s.error_message?`<small>${esc(s.error_message)}</small>`:''}</td><td class="diag-preview">${esc(s.text_preview||'?')}</td><td>${fileState(s)} ? ${bytes(s.actual_size_bytes)}</td><td>${s.duration_ms?`${(s.duration_ms/1000).toFixed(1)}s`:'?'}</td><td class="diag-actions"><button onclick="openSegmentDiagnostics(${s.id})">Chi ti?t</button>${['failed','interrupted'].includes(s.status)?`<button onclick="retrySegmentAction(${s.id})">Th? l?i</button>`:''}</td></tr>`).join('')}</tbody></table></div><h3>Artifacts (${data.artifacts.length})</h3>${data.artifacts.length?`<div class="diag-table-wrap"><table class="diag-table"><thead><tr><th>Lo?i</th><th>Tr?ng th?i</th><th>File</th><th>Kich thu?c</th></tr></thead><tbody>${data.artifacts.map(a=>`<tr><td>${esc(a.artifact_type)}</td><td>${statusBadge(a.status)}</td><td>${fileState(a)} ? ${esc(a.filename||'?')}</td><td>${bytes(a.actual_size_bytes)}</td></tr>`).join('')}</tbody></table></div>`:'<p class="muted">Ch?a co artifact.</p>'}`;$('#jobDiagnosticsDialog').close();$('#segmentDiagnosticsDialog').close();if(!$('#chapterDiagnosticsDialog').open)$('#chapterDiagnosticsDialog').showModal()}catch(e){toast(e.message,true)}}
async function openSegmentDiagnostics(id){try{const s=await api(`/api/diagnostics/segments/${id}`);state.diagnosticSegmentId=id;state.diagnosticChapterId=s.job_chapter_id;$('#segmentDiagnosticTitle').textContent=`Segment #${s.segment_index} ? Ch??ng ${s.chapter_number}`;$('#segmentDiagnosticBody').innerHTML=`<div class="diag-line">${statusBadge(s.status)}<span>L?n th?: ${s.attempt_count}</span><span>Th?i lu?ng: ${s.duration_ms?`${(s.duration_ms/1000).toFixed(2)}s`:'?'}</span></div>${s.error_message?`<div class="issue">${esc(s.error_message)}</div>`:''}<h3>Text d?u vao</h3><pre class="segment-text">${esc(s.text_preview||'Khong doc duoc text blob.')}</pre><div class="file-grid"><div><strong>Text blob</strong>${fileState(s.text_file)}<span>${bytes(s.text_file.actual_size_bytes)}</span></div><div><strong>WAV segment</strong>${fileState(s.audio_file)}<span>${bytes(s.audio_file.actual_size_bytes)}</span></div></div><div class="diag-actions">${['failed','interrupted'].includes(s.status)?`<button class="primary" onclick="retrySegmentAction(${s.id})">Th? l?i segment nay</button>`:''}${s.status==='verified'?`<button ${runtimeAllowsMutation()?'':regenerateMutationAttr} onclick="regenerateSegment(${s.id})">${regenerateButtonLabel}</button>`:''}</div><div id="segmentAttemptsContainer"></div>`;$('#chapterDiagnosticsDialog').close();if(!$('#segmentDiagnosticsDialog').open)$('#segmentDiagnosticsDialog').showModal();if(s.status==='verified')refreshSegmentAttempts(s.id)}catch(e){toast(e.message,true)}}
async function retryChapter(id){if(!runtimeAllowsMutation()){toast('Runtime identity must be resolved before mutating actions.',true);return}try{const r=await api(`/api/job-chapters/${id}/retry`,{method:'POST',body:'{}'});toast(`Đã xếp lại chương; giữ nguyên ${r.verified_segments_reused} segment hợp lệ.`);$('#chapterDiagnosticsDialog').close();await loadJobs();await openJobDiagnostics(state.diagnosticJobId)}catch(e){toast(e.message,true)}}
async function retrySegmentAction(id){if(!runtimeAllowsMutation()){toast('Runtime identity must be resolved before mutating actions.',true);return}try{await api(`/api/segments/${id}/retry`,{method:'POST',body:'{}'});toast('Đã xếp lại segment lỗi; các segment hợp lệ được giữ nguyên.');$('#segmentDiagnosticsDialog').close();await loadJobs();await openJobDiagnostics(state.diagnosticJobId)}catch(e){toast(e.message,true)}}

window.openJobDiagnostics=openJobDiagnostics;window.openChapterDiagnostics=openChapterDiagnostics;window.openSegmentDiagnostics=openSegmentDiagnostics;window.retryChapter=retryChapter;window.retrySegmentAction=retrySegmentAction;

// Segment Regeneration UI
const regenerateMutationAttr='data-runtime-mutation-control disabled title="Resolve runtime identity before regenerating"';
// status==='verified' gates the regenerate control in the diagnostics UI contract.
const regenerateEligibleStatus='verified';
const regenerateButtonLabel='Regenerate Verified Segment';
const retryableSegmentStatuses=['failed','interrupted'];
async function regenerateSegment(segmentId) {
  if(!runtimeAllowsMutation()){toast('Runtime identity must be resolved before mutating actions.',true);return}
  try {
    const result = await api(`/api/segments/${segmentId}/regenerate`, {method: 'POST', body: '{}'});
    state.segmentCandidate = {segmentId, attemptId: result.attempt_id, attemptNumber: result.attempt_number};
    await refreshSegmentAttempts(segmentId);
    toast(`Candidate ${result.attempt_number} generated (${(result.duration_ms/1000).toFixed(2)}s)`);
  } catch(e) {
    toast(e.message, true);
  }
}

async function refreshSegmentAttempts(segmentId) {
  try {
    const data = await api(`/api/segments/${segmentId}/attempts`);
    state.segmentAttempts = data;
    renderSegmentAttempts(segmentId);
  } catch(e) {
    toast(e.message, true);
  }
}

function renderSegmentAttempts(segmentId) {
  const data = state.segmentAttempts;
  if (!data) return;

  const container = $('#segmentAttemptsContainer');
  if (!container) return;

  let html = '<h3>Segment Attempts</h3><div class="attempts-grid">';

  if (data.active_attempt) {
    html += `<div class="attempt-card active"><strong>Active (Attempt ${data.active_attempt.attempt_number})</strong>`;
    html += `<span>${(data.active_attempt.duration_ms/1000).toFixed(2)}s</span>`;
    html += `<audio controls src="/api/segments/${segmentId}/audio"></audio>`;
    if (regenerateEligibleStatus==='verified' && !data.candidate) {
      html += `<div class="attempt-actions"><button class="secondary" ${runtimeAllowsMutation()?'':regenerateMutationAttr} onclick="regenerateSegment(${segmentId})">${regenerateButtonLabel}</button></div>`;
    }
    html += `</div>`;
  }

  if (data.candidate) {
    html += `<div class="attempt-card candidate"><strong>Candidate (Attempt ${data.candidate.attempt_number})</strong>`;
    html += `<span>${(data.candidate.duration_ms/1000).toFixed(2)}s</span>`;
    html += `<audio controls src="/api/segment-attempts/${data.candidate.attempt_id}/audio"></audio>`;
    html += `<div class="attempt-actions">`;
    html += `<button class="primary" onclick="acceptCandidate(${segmentId}, ${data.candidate.attempt_id})">Accept</button>`;
    html += `<button class="ghost" onclick="rejectCandidate(${segmentId}, ${data.candidate.attempt_id})">Reject</button>`;
    html += `</div></div>`;
  }

  if (data.history && data.history.length > 0) {
    html += '<details><summary>History</summary>';
    data.history.forEach(h => {
      html += `<div class="attempt-card history"><span>Attempt ${h.attempt_number} (${h.status})</span>`;
      html += `<span>${(h.duration_ms/1000).toFixed(2)}s</span></div>`;
    });
    html += '</details>';
  }

  html += '</div>';
  container.innerHTML = html;
}

async function acceptCandidate(segmentId, attemptId) {
  if (!confirm('Accept this candidate? This will rebuild the chapter artifact.')) return;
  try {
    await api(`/api/segments/${segmentId}/accept-candidate`, {method: 'POST', body: JSON.stringify({attempt_id: attemptId})});
    toast('Candidate accepted and chapter rebuilt');
    state.segmentCandidate = null;
    await refreshSegmentAttempts(segmentId);
  } catch(e) {
    toast(e.message, true);
  }
}

async function rejectCandidate(segmentId, attemptId) {
  try {
    await api(`/api/segments/${segmentId}/reject-candidate`, {method: 'POST', body: JSON.stringify({attempt_id: attemptId})});
    toast('Candidate rejected');
    state.segmentCandidate = null;
    await refreshSegmentAttempts(segmentId);
  } catch(e) {
    toast(e.message, true);
  }
}

window.regenerateSegment = regenerateSegment;
window.acceptCandidate = acceptCandidate;
window.rejectCandidate = rejectCandidate;
window.refreshSegmentAttempts = refreshSegmentAttempts;
async function refreshLibrary(){if(state.libraryBusy)return;state.libraryBusy=true;$('#refreshLibrary').disabled=true;$('#libraryStatus').textContent='Loading voices…';$('#libraryError').classList.add('hidden');try{const activeOnly=!state.showInactive;state.libraryVoices=await api(`/api/custom-voices?active_only=${activeOnly}`);renderLibraryVoices();$('#libraryStatus').textContent=`${state.libraryVoices.length} voice${state.libraryVoices.length===1?'':'s'}${activeOnly?' (active only)':''}`}catch(e){$('#libraryStatus').textContent='Error loading voices';showLibraryError(mapLibraryError(e.message))}finally{state.libraryBusy=false;$('#refreshLibrary').disabled=false}}
function renderLibraryVoices(){const container=$('#libraryVoiceList');if(!state.libraryVoices||state.libraryVoices.length===0){container.innerHTML='<p class="muted">No voices found.</p>';if(state.selectedVoiceId){state.selectedVoiceId=null;$('#librarySelectedDetails').classList.add('hidden')}return}container.innerHTML=state.libraryVoices.map(v=>`<div class="voice-library-row ${state.selectedVoiceId===v.id?'selected':''}" data-voice-id="${v.id}"><strong>${esc(v.display_name)}</strong><span class="muted">${v.is_active?'Active':'Inactive'}${v.description?' · '+esc(v.description):''}</span></div>`).join('');container.querySelectorAll('.voice-library-row').forEach(el=>el.onclick=()=>selectLibraryVoice(+el.dataset.voiceId));if(state.selectedVoiceId&&!state.libraryVoices.find(v=>v.id===state.selectedVoiceId)){state.selectedVoiceId=null;$('#librarySelectedDetails').classList.add('hidden')}}
function selectLibraryVoice(id){const voice=state.libraryVoices?.find(v=>v.id===id);if(!voice)return;state.selectedVoiceId=id;state.previewRevisionId=null;state.libraryRevisions=[];renderLibraryVoices();$('#librarySelectedDetails').classList.remove('hidden');$('#libraryVoiceInfoName').textContent=voice.display_name;$('#libraryVoiceInfoStatus').textContent=voice.is_active?'Active':'Inactive';$('#libraryVoiceInfoStatus').className=voice.is_active?'voice-info-badge badge-active':'voice-info-badge badge-inactive';if(voice.description&&voice.description.trim()){$('#libraryVoiceInfoDescription').textContent=voice.description;$('#libraryVoiceInfoDescription').classList.remove('muted')}else{$('#libraryVoiceInfoDescription').textContent='No description';$('#libraryVoiceInfoDescription').classList.add('muted')}$('#libraryDeactivate').disabled=!voice.is_active||state.libraryBusy;$('#libraryDeactivate').classList.toggle('hidden',!voice.is_active);$('#libraryReactivate').disabled=voice.is_active||state.libraryBusy;$('#libraryReactivate').classList.toggle('hidden',voice.is_active);$('#libraryAudioFile').disabled=false;$('#libraryTranscript').disabled=false;$('#libraryTranscript').value='';$('#libraryTranscriptCounter').textContent='0 / 10000';$('#libraryUploadRevision').disabled=false;$('#libraryUploadStatus').textContent='';$('#libraryUploadError').classList.add('hidden');$('#libraryUploadTargetVoice').textContent=voice.display_name;$('#libraryPreviewBox').classList.add('hidden');const audio=$('#libraryPreviewAudio');audio.pause();audio.removeAttribute('src');loadLibraryRevisions()}
async function createLibraryVoice(){if(state.libraryBusy)return;const name=$('#libraryNewName').value.trim();const description=$('#libraryNewDescription').value.trim();$('#libraryError').classList.add('hidden');if(!name){showLibraryError('Voice name is required.');$('#libraryNewName').focus();return}if(name.length>120){showLibraryError('Voice name must be 120 characters or less.');$('#libraryNewName').focus();return}state.libraryBusy=true;$('#libraryCreate').disabled=true;try{const voice=await api('/api/custom-voices',{method:'POST',body:JSON.stringify({display_name:name,description:description||null})});toast(`Created voice: ${voice.display_name}`);$('#libraryNewName').value='';$('#libraryNewDescription').value='';await refreshLibrary();state.selectedVoiceId=voice.id;renderLibraryVoices();selectLibraryVoice(voice.id)}catch(e){showLibraryError(mapLibraryError(e.message))}finally{state.libraryBusy=false;$('#libraryCreate').disabled=false}}
async function deactivateLibraryVoice(){if(!state.selectedVoiceId||state.libraryBusy)return;state.libraryBusy=true;$('#libraryDeactivate').disabled=true;$('#libraryReactivate').disabled=true;$('#libraryError').classList.add('hidden');try{await api(`/api/custom-voices/${state.selectedVoiceId}/deactivate`,{method:'PATCH',body:'{}'});toast('Voice deactivated');await refreshLibrary()}catch(e){showLibraryError(mapLibraryError(e.message))}finally{state.libraryBusy=false;if(state.selectedVoiceId){const voice=state.libraryVoices?.find(v=>v.id===state.selectedVoiceId);$('#libraryDeactivate').disabled=!voice||!voice.is_active;$('#libraryReactivate').disabled=!voice||voice.is_active}}}
async function reactivateLibraryVoice(){if(!state.selectedVoiceId||state.libraryBusy)return;state.libraryBusy=true;$('#libraryDeactivate').disabled=true;$('#libraryReactivate').disabled=true;$('#libraryError').classList.add('hidden');try{await api(`/api/custom-voices/${state.selectedVoiceId}/reactivate`,{method:'PATCH',body:'{}'});toast('Voice reactivated');await refreshLibrary();selectLibraryVoice(state.selectedVoiceId)}catch(e){showLibraryError(mapLibraryError(e.message))}finally{state.libraryBusy=false;if(state.selectedVoiceId){const voice=state.libraryVoices?.find(v=>v.id===state.selectedVoiceId);$('#libraryDeactivate').disabled=!voice||!voice.is_active;$('#libraryReactivate').disabled=!voice||voice.is_active}}}
function showLibraryError(msg){const el=$('#libraryError');el.textContent=msg;el.classList.remove('hidden')}
function mapLibraryError(msg){if(!msg)return 'The custom voice service is currently unavailable.';const lower=msg.toLowerCase();if(lower.includes('invalid')||lower.includes('bad request'))return 'The custom voice information is invalid.';if(lower.includes('not found'))return 'The selected custom voice no longer exists.';if(lower.includes('conflict')||lower.includes('already exists'))return 'This custom voice could not be updated because its state changed.';if(lower.includes('unavailable')||lower.includes('internal'))return 'The custom voice service is currently unavailable.';return 'Could not connect to the custom voice service.'}
async function loadLibraryRevisions(){if(!state.selectedVoiceId)return;$('#libraryRevisionsStatus').textContent='Loading revisions...';$('#libraryRevisionsList').innerHTML='';try{state.libraryRevisions=await api(`/api/custom-voices/${state.selectedVoiceId}/revisions`);renderLibraryRevisions();$('#libraryRevisionsStatus').textContent=`${state.libraryRevisions.length} revision${state.libraryRevisions.length===1?'':'s'}`}catch(e){$('#libraryRevisionsStatus').textContent='Error loading revisions';$('#libraryRevisionsList').innerHTML=`<p class="muted error-text">${esc(mapLibraryUploadError(e.message))}</p>`}}
function renderLibraryRevisions(){const container=$('#libraryRevisionsList');if(!state.libraryRevisions||state.libraryRevisions.length===0){container.innerHTML='<p class="muted">No revisions yet. Upload reference audio to create the first revision.</p>';renderTestRevisionSelect();return}const voiceName=state.libraryVoices.find(v=>v.id===state.selectedVoiceId)?.display_name||'Unknown';const selectedVoice=state.libraryVoices.find(v=>v.id===state.selectedVoiceId);const preferredRevisionId=selectedVoice?.preferred_synthesis_revision_id;container.innerHTML=state.libraryRevisions.map(r=>{const isPreferred=preferredRevisionId===r.id;const date=new Date(r.created_at).toLocaleString('en-US',{month:'short',day:'numeric',year:'numeric'});return `<div class="library-revision-row${isPreferred?' preferred':''}" data-revision-id="${r.id}"><div class="revision-content"><div><strong>Revision ${r.revision_number}</strong> · ${(r.duration_ms/1000).toFixed(1)}s · ${date}${isPreferred?' <span class="pill preferred-badge">Used for synthesis</span>':''}</div><details class="revision-technical-details"><summary>Technical details</summary><div class="revision-meta"><span>ID: ${r.id}</span><span>Sample rate: ${r.sample_rate}Hz</span><span>Channels: ${r.channels}</span><span>Format: ${r.audio_format}</span><span>Created: ${new Date(r.created_at).toLocaleString('en-US',{dateStyle:'medium',timeStyle:'short'})}</span></div></details></div><div class="revision-actions"><button class="ghost listen-revision-btn" onclick="playReferenceAudio(${r.id})" title="Listen to original reference audio">Listen reference</button>${!isPreferred?`<button class="ghost set-preferred-btn" onclick="setPreferredSynthesisRevision(${r.id})" title="Use this revision for synthesis">Use for synthesis</button>`:''}</div></div>`}).join('');renderTestRevisionSelect()}
function renderTestRevisionSelect(){const voiceInput=$('#libraryTestVoice');const selectElem=$('#libraryTestRevisionSelect');const generateBtn=$('#libraryGenerateTestAudio');const selectedVoice=state.libraryVoices?.find(v=>v.id===state.selectedVoiceId);if(!selectedVoice){voiceInput.value='';selectElem.innerHTML='<option value="">Choose a revision</option>';selectElem.disabled=true;generateBtn.disabled=true;return}voiceInput.value=selectedVoice.display_name;if(!state.libraryRevisions||state.libraryRevisions.length===0){selectElem.innerHTML='<option value="">No revisions available</option>';selectElem.disabled=true;generateBtn.disabled=true;return}const preferredRevisionId=selectedVoice.preferred_synthesis_revision_id;const options=['<option value="">Choose a revision</option>'];options.push(...state.libraryRevisions.map(r=>{const isPreferred=preferredRevisionId===r.id;const label=`${selectedVoice.display_name} — Revision ${r.revision_number} — ${(r.duration_ms/1000).toFixed(1)}s${isPreferred?' — Used for synthesis':''}`;return `<option value="${r.id}"${state.previewRevisionId===r.id?' selected':''}>${esc(label)}</option>`}));selectElem.innerHTML=options.join('');selectElem.disabled=false;generateBtn.disabled=!state.previewRevisionId}
function testVoiceRevision(id){const revision=state.libraryRevisions?.find(r=>r.id===id);if(!revision)return;state.previewRevisionId=id;renderTestRevisionSelect();$('#libraryPreviewBox').classList.add('hidden');const previewAudio=$('#libraryPreviewAudio');previewAudio.pause();previewAudio.removeAttribute('src')}
function playReferenceAudio(revisionId){const audio=$('#libraryReferenceAudio');const currentSrc=audio.src;const expectedSrc=`/api/custom-voice-revisions/${revisionId}/audio`;if(currentSrc.startsWith(expectedSrc)&&!audio.paused){audio.pause();return}audio.pause();audio.removeAttribute('src');audio.onloadstart=null;audio.onloadedmetadata=()=>{audio.play().catch(err=>toast('Cannot play reference audio',true))};audio.onerror=()=>{const errCode=audio.error?.code;let msg='Reference audio unavailable';if(errCode===4)msg='Reference audio format not supported';else if(errCode===3)msg='Reference audio could not be decoded';else if(errCode===2)msg='Reference audio network error';toast(msg,true)};audio.src=`${expectedSrc}?v=${Date.now()}`;audio.load()}
function updatePreviewTextCounter(){const text=$('#libraryPreviewText').value;$('#libraryPreviewTextCounter').textContent=`${text.length} / 500`}
function useDefaultPreviewText(){$('#libraryPreviewText').value='';updatePreviewTextCounter()}
async function uploadLibraryRevision(){if(state.uploadBusy||!state.selectedVoiceId)return;const capturedVoiceId=state.selectedVoiceId;const capturedVoice=state.libraryVoices?.find(v=>v.id===capturedVoiceId);if(!capturedVoice){showLibraryUploadError('No voice selected.');return}const fileInput=$('#libraryAudioFile');const transcript=$('#libraryTranscript').value.trim();$('#libraryUploadError').classList.add('hidden');$('#libraryUploadStatus').textContent='';if(!fileInput.files||!fileInput.files[0]){showLibraryUploadError('Please select a reference audio file.');return}if(!transcript){showLibraryUploadError('Please enter the exact transcript for the reference audio.');$('#libraryTranscript').focus();return}if(transcript.length>10000){showLibraryUploadError('Transcript is too long (max 10,000 characters).');$('#libraryTranscript').focus();return}const file=fileInput.files[0];if(file.size===0){showLibraryUploadError('Audio file is empty.');return}if(file.size>52428800){showLibraryUploadError('The reference audio file is too large (max 50MB).');return}state.uploadBusy=true;$('#libraryUploadRevision').disabled=true;$('#libraryUploadStatus').textContent=`Uploading to ${capturedVoice.display_name}...`;try{const formData=new FormData();formData.append('audio',file);formData.append('transcript',transcript);const result=await fetch(`/api/custom-voices/${capturedVoiceId}/revisions`,{method:'POST',body:formData});let data;try{data=await result.json()}catch{data={detail:await result.text()}}if(!result.ok)throw new Error(data.detail||data.error||'Upload failed');$('#libraryUploadStatus').textContent=`Revision ${data.revision_number||'created'} uploaded to ${capturedVoice.display_name}`;fileInput.value='';$('#libraryTranscript').value='';$('#libraryTranscriptCounter').textContent='0 / 10000';if(state.selectedVoiceId===capturedVoiceId){await loadLibraryRevisions()}}catch(e){showLibraryUploadError(mapLibraryUploadError(e.message))}finally{state.uploadBusy=false;$('#libraryUploadRevision').disabled=false}}
function showLibraryUploadError(msg){const el=$('#libraryUploadError');el.textContent=msg;el.classList.remove('hidden')}
function mapLibraryUploadError(msg){if(!msg)return 'The custom voice service is currently unavailable.';const lower=msg.toLowerCase();if(lower.includes('invalid')||lower.includes('bad request')||lower.includes('transcript')||lower.includes('audio'))return 'The reference audio or transcript is invalid.';if(lower.includes('not found'))return 'The selected custom voice no longer exists.';if(lower.includes('conflict'))return 'The custom voice changed while the request was being processed.';if(lower.includes('too large')||lower.includes('size')||lower.includes('413'))return 'The reference audio file is too large.';if(lower.includes('unavailable')||lower.includes('internal')||lower.includes('503'))return 'The custom voice service is currently unavailable.';if(lower.includes('network')||lower.includes('fetch'))return 'Could not connect to the custom voice service.';return 'The reference audio or transcript is invalid.';}
async function generateTestAudio(){if(state.previewBusy||!state.previewRevisionId)return;const revision=state.libraryRevisions?.find(r=>r.id===state.previewRevisionId);const selectedVoice=state.libraryVoices?.find(v=>v.id===state.selectedVoiceId);if(!revision||!selectedVoice){toast('Please select a revision to test first',true);return}const requestVoiceId=state.selectedVoiceId;const requestRevisionId=state.previewRevisionId;const button=$('#libraryGenerateTestAudio');const originalText=button.textContent;state.previewBusy=true;button.disabled=true;button.textContent='Generating…';$('#libraryPreviewBox').classList.add('hidden');try{const previewText=$('#libraryPreviewText').value.trim();const payload={custom_voice_revision_id:Number(requestRevisionId)};if(previewText)payload.preview_text=previewText;const result=await api('/api/voice-previews',{method:'POST',body:JSON.stringify(payload)});if(state.selectedVoiceId!==requestVoiceId||state.previewRevisionId!==requestRevisionId){return}const audio=$('#libraryPreviewAudio');audio.src=`${result.audio_url}?v=${result.cache_key}`;await audio.load();$('#libraryPreviewBox').classList.remove('hidden');const provenance=`Generated with ${selectedVoice.display_name} — Revision ${revision.revision_number}`;$('#libraryPreviewProvenance').textContent=provenance;await audio.play().catch(()=>{})}catch(e){const lower=e.message.toLowerCase();let msg='Preview generation failed';if(lower.includes('not found')||lower.includes('404'))msg='The selected voice revision is unavailable.';else if(lower.includes('unavailable')||lower.includes('503'))msg='The custom voice service is currently unavailable.';else if(lower.includes('network')||lower.includes('fetch'))msg='Could not connect to the custom voice service.';toast(msg,true)}finally{state.previewBusy=false;if(state.selectedVoiceId===requestVoiceId&&state.previewRevisionId===requestRevisionId){button.disabled=false;button.textContent=originalText}}}
function outputBadge(job){if(job.is_active_output)return '<span class="badge active-output">ACTIVE OUTPUT</span>';if(job.is_historical_output)return '<span class="badge historical">HISTORICAL</span>';return ''}
function jobOutputMeta(job){if(job.is_active_output&&job.active_output_chapters?.length){const chapter=job.active_output_chapters[0],plan=chapter.active_output_casting_plan_revision?` | Plan v${chapter.active_output_casting_plan_revision}`:'';return `Active chapter output: ${chapter.chapter_number}. ${chapter.chapter_title}${plan}`}if(job.is_historical_output)return 'Historical evidence only - not the current chapter output';return ''}
