async function setPreferredSynthesisRevision(revisionId){if(state.libraryBusy||!state.selectedVoiceId)return;const selectedVoice=state.libraryVoices.find(v=>v.id===state.selectedVoiceId);if(!selectedVoice)return;if(selectedVoice.preferred_synthesis_revision_id===revisionId){toast('This revision is already preferred for synthesis');return}state.libraryBusy=true;try{const result=await api(`/api/custom-voices/${state.selectedVoiceId}/preferred-revision`,{method:'PATCH',body:JSON.stringify({revision_id:revisionId})});selectedVoice.preferred_synthesis_revision_id=result.preferred_synthesis_revision_id;renderLibraryRevisions();toast(`Revision ${state.libraryRevisions.find(r=>r.id===revisionId)?.revision_number||revisionId} set as preferred for synthesis`)}catch(e){toast(e.message,true)}finally{state.libraryBusy=false}}
